          <div style={{position:"absolute",inset:0,background:`linear-gradient(180deg, #1a0a04 0%, ${dpCurrentPick===0?"#2a1005":dpCurrentPick===1?"#0a1830":"#1a0830"} 50%, #0a0618 100%)`}}/>
